/*
* Returns a String for the header subscreen to display the title of the page
*
* by Mateo Rada Arias
*/

return "ACCUMULATIONS REPORT ";

/*
* By Diego Tapia
*/

const currentUser = ProcessMaker.user.id;
let CQP_SEARCH = this.CQP_SEARCH 
let START_DATE = this.START_DATE
let END_DATE = this.END_DATE
let code = ""

try {
    $("#recordScreenContainer").css("max-width", "97%");
} catch (error) {}

if (CQP_SEARCH !== undefined) {
    var data = {
        CQP_SEARCH: CQP_SEARCH,
        START_DATE: START_DATE,
        END_DATE: END_DATE,
        currentUserId: currentUser
    };

    var jsonData = JSON.stringify(data);
    var encodedData = encodeURIComponent(jsonData);

    //Get window height
    var screenHeight = 768;

    if (typeof top.innerHeight != 'undefined') {
        screenHeight = top.innerHeight - 310;
    }

    code = `<body style="margin:0px;padding:0px;overflow:hidden;width:` + screenHeight + `px">
        <iframe id='bulkIframe' src="/api/1.0/pstools/script/cqp_accumulations_report?data=` + encodedData + `" frameborder="0" 
                style="overflow:hidden;overflow-x:hidden;overflow-y:hidden;height:` + screenHeight + `px;width:100%;top:110px;left:0px;right:0px;bottom:0px" 
        ></iframe>
    </body>`;
}

return code;

/*
* By Diego Tapia
*/

let file = this.content
if (file != null && file != undefined && file != "") {
    file = file.fileContents

    if (file != null && file != "" && file != undefined ) {
        const dateObj = new Date();
        var a = document.createElement("a");
        a.href = "data:application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;base64," + file; 
        a.download = "accumulation-report_" + (dateObj.getUTCMonth() + 1) + "_" + dateObj.getUTCDate() + "_" + dateObj.getUTCFullYear() + ".xlsx";
        a.click(); 
        window.generated = false
    }

    window.generated = false
}

/*
* By Diego Tapia
*/

let EXPORT_REPORT = this.EXPORT_REPORT
let parameters = {}
const iframeElement = document.getElementById('bulkIframe')

if (iframeElement != null && iframeElement != undefined && iframeElement != "") {
    parameters.query = iframeElement.contentWindow.sqlQuery

    parameters.columns = JSON.parse(JSON.stringify(iframeElement.contentWindow.responseFormat)).map(obj => {
        const newObj = {...obj};

        if (newObj.variable.endsWith("_SHARE")) {
            newObj.format = "percentage";
        }
        
        return newObj;
    });
    
    parameters.columns.splice(0, 1);
    return escape(JSON.stringify(parameters));
}

return escape(JSON.stringify(parameters));

/*
* By Diego Tapia
*/

let EXPORT_REPORT = this.EXPORT_REPORT
let parameters = {}
const iframeElement = document.getElementById('bulkIframe')

if (iframeElement != null && iframeElement != undefined && iframeElement != "") {
    parameters.startColumn = iframeElement.contentWindow.startColumn
    parameters.headers = JSON.parse(JSON.stringify(iframeElement.contentWindow.headerConfiguration))

    parameters.collectionConf = JSON.parse(JSON.stringify(iframeElement.contentWindow.collectionConf)).map(obj => {
        const newObj = {...obj};
        delete newObj.CQP_COUNTRIES;
        delete newObj.CQP_MAX_CAP;
        delete newObj.CQP_REINSURER_NAME;
        delete newObj.CQP_COLOR;
        return newObj;
    });

    return escape(JSON.stringify(parameters));
}

return escape(JSON.stringify(parameters));
